INSERT INTO IELTSQuestion (sectionId, questionIndex, questionType, questionText, options, correctAnswer, acceptableAnswers, passageText, score, answerExplanation, createdAt) VALUES
(18014, 31, 'fill_blank', NULL, NULL, 'fences', NULL, '## [note]\n## Elephant translocation\n\n## Reasons for overpopulation at Majete National Park\n● strict enforcement of anti-poaching laws\n● successful breeding\n\n## Problems caused by elephant overpopulation\n● greater competition, causing hunger for elephants\n● damage to {Q31} in the park\n\n## The translocation process\n● a suitable group of elephants from the same {Q32} was selected\n● vets and park staff made use of {Q33} to help guide the elephants into an open plain\n● elephants were immobilised with tranquilisers\n  – this process had to be completed quickly to reduce {Q34}\n  – elephants had to be turned on their {Q35} to avoid damage to their lungs\n● elephants\' {Q36} had to be monitored constantly\n● tracking devices were fitted to the matriarchs\n● data including the size of their tusks and {Q37} was taken\n● elephants were taken by truck to their new reserve\n\n## Advantages of translocation at Nkhotakota Wildlife Park\n● {Q38} opportunities\n● a reduction in the number of poachers and {Q39}\n● an example of conservation that other parks can follow\n● an increase in {Q40} as a contributor to GDP', 1, NULL, NOW());
